import{c as t,Q as o,j as a,m as i}from"./chunks/framework.BPKcPtvA.js";const m=JSON.parse('{"title":"Multi-Factor Authentication","description":"","frontmatter":{},"headers":[],"relativePath":"guide/account/multi-factor-authentication.md","filePath":"guide/account/multi-factor-authentication.md","lastUpdated":1778862269000}'),n={name:"guide/account/multi-factor-authentication.md"};function r(s,e,l,c,d,h){return o(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="multi-factor-authentication" tabindex="-1">Multi-Factor Authentication <a class="header-anchor" href="#multi-factor-authentication" aria-label="Permalink to &quot;Multi-Factor Authentication&quot;">​</a></h1><p>Multi-factor authentication (MFA) adds a second verification step on top of your password. The Console supports four MFA methods. You can enrol in more than one — the more methods you have, the easier it is to recover if you lose access to a device.</p><p>Manage MFA from the <strong>Multi-Factor Authentication</strong> section of your <a href="./managing-your-account">Account</a> page.</p><h2 id="available-methods" tabindex="-1">Available methods <a class="header-anchor" href="#available-methods" aria-label="Permalink to &quot;Available methods&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>What it is</th><th>When to use</th></tr></thead><tbody><tr><td><strong>Authenticator App (TOTP)</strong></td><td>A 6-digit code refreshed every 30 seconds, generated by an app such as Google Authenticator, Microsoft Authenticator, or 1Password.</td><td>Best balance of security and convenience. Works offline. Recommended default.</td></tr><tr><td><strong>Email OTP</strong></td><td>A one-time code emailed to you.</td><td>Fallback when you do not have a phone.</td></tr><tr><td><strong>SMS OTP</strong></td><td>A one-time code sent to your verified phone number.</td><td>Available if your organisation enables it; less secure than TOTP.</td></tr><tr><td><strong>Passkey / Security Key</strong></td><td>A WebAuthn credential bound to a device or hardware key.</td><td>Strongest option. Phishing-resistant.</td></tr></tbody></table><p>Your organisation chooses which of these are allowed. If a method is not listed in your Account page, your customer&#39;s admin has not enabled it.</p><h2 id="enrolling-an-authenticator-app-totp" tabindex="-1">Enrolling an Authenticator App (TOTP) <a class="header-anchor" href="#enrolling-an-authenticator-app-totp" aria-label="Permalink to &quot;Enrolling an Authenticator App (TOTP)&quot;">​</a></h2><ol><li>Click <strong>Set up Authenticator App</strong>.</li><li>A modal appears with a QR code and a manual secret string.</li><li>Open your authenticator app and either scan the QR code or paste the secret.</li><li>The app starts generating 6-digit codes.</li><li>Enter the current code into the verification field and click <strong>Verify</strong>.</li><li>The method is now active and shows in your enabled list.</li></ol><h2 id="enabling-email-otp" tabindex="-1">Enabling Email OTP <a class="header-anchor" href="#enabling-email-otp" aria-label="Permalink to &quot;Enabling Email OTP&quot;">​</a></h2><ol><li>Click <strong>Enable Email OTP</strong>.</li><li>A test code is sent to your verified email.</li><li>Enter the code to confirm receipt.</li><li>Email OTP is enabled.</li></ol><h2 id="adding-a-passkey" tabindex="-1">Adding a Passkey <a class="header-anchor" href="#adding-a-passkey" aria-label="Permalink to &quot;Adding a Passkey&quot;">​</a></h2><ol><li>Click <strong>Add Passkey</strong>.</li><li>You will be sent an email with a setup link.</li><li>Open the link on the device or hardware key you want to enrol.</li><li>Follow the system prompt to create the passkey.</li><li>The passkey is registered against your account.</li></ol><p>Passkeys are managed by the operating system or browser, not the Console. If you lose the device, remove the passkey here and enrol a new one.</p><h2 id="removing-a-method" tabindex="-1">Removing a method <a class="header-anchor" href="#removing-a-method" aria-label="Permalink to &quot;Removing a method&quot;">​</a></h2><p>Click the <strong>Remove</strong> button next to the method. A confirmation modal warns you about losing access. If this is your only method and your organisation enforces MFA, the Console will block removal — add a replacement first.</p><h2 id="recovering-if-you-lose-access" tabindex="-1">Recovering if you lose access <a class="header-anchor" href="#recovering-if-you-lose-access" aria-label="Permalink to &quot;Recovering if you lose access&quot;">​</a></h2><p>If you cannot sign in because all of your MFA devices are lost:</p><ol><li>Contact your customer admin (for customer users) or an Exto operator (for internal users).</li><li>They can reset your MFA setup from the user detail page. You will be prompted to enrol again on your next sign-in.</li></ol><p>There is no self-service recovery — this is intentional. Account recovery requires a human in the loop.</p><h2 id="mfa-enforcement" tabindex="-1">MFA enforcement <a class="header-anchor" href="#mfa-enforcement" aria-label="Permalink to &quot;MFA enforcement&quot;">​</a></h2><p>Customer admins can configure whether MFA is <strong>required</strong> or <strong>optional</strong> for users in their organisation. Settings live in the Customer Portal under <strong>Settings → Security</strong>. If MFA is required and you have not enrolled yet, the Console will guide you through it on first sign-in.</p>',21)])])}const p=t(n,[["render",r]]);export{m as __pageData,p as default};
